import { describe, expect, it } from 'vitest';

import {
  admitImpulse,
  countSharp,
  impulseFrames,
  ImpulsiveEventMaster,
  mixed,
  oneSharp,
  onsetSharpness,
  sharpThreshold,
  sustainedFrames,
  threeSharp,
  type NodeReport,
} from '../src/impulsive-event-admission';

describe('onsetSharpness (mirrors onsetSharpness)', () => {
  it('is zero for empty and single-frame windows', () => {
    expect(onsetSharpness([])).toBe(0);
    expect(onsetSharpness([42])).toBe(0);
  });

  it('is zero for a constant (flat) window', () => {
    expect(onsetSharpness([5, 5, 5, 5])).toBe(0);
  });

  it('is the largest single-frame rise; decays contribute zero', () => {
    // [2,3,90,40,10]: rises 1, 87, 0 (decay), 0 (decay) -> max 87
    expect(onsetSharpness(impulseFrames)).toBe(87);
  });

  it('a gradual climb has a small per-frame rise', () => {
    // [10,20,30,40,50]: rises all 10 -> max 10
    expect(onsetSharpness(sustainedFrames)).toBe(10);
  });

  it('near-identical total energy (145 vs 150) with different onset shape', () => {
    const total = (xs: readonly number[]) => xs.reduce((a, b) => a + b, 0);
    expect(total(impulseFrames)).toBe(145);
    expect(total(sustainedFrames)).toBe(150);
  });
});

describe('countSharp (mirrors countSharp)', () => {
  it('counts detected reports clearing the sharpness threshold', () => {
    expect(countSharp(sharpThreshold, threeSharp)).toBe(3);
    expect(countSharp(sharpThreshold, oneSharp)).toBe(1);
  });

  it('does not count a sustained (sub-threshold) report', () => {
    // mixed = [sharp 87, sustained 10]; only the sharp one counts
    expect(countSharp(sharpThreshold, mixed)).toBe(1);
    expect(countSharp(sharpThreshold, mixed)).toBe(
      countSharp(sharpThreshold, oneSharp),
    );
  });

  it('does not count an undetected node even at high sharpness', () => {
    const silent: NodeReport = { sharpness: 99, detected: false };
    expect(countSharp(sharpThreshold, [silent])).toBe(0);
  });
});

describe('promotion check: admitImpulse', () => {
  it('admits at quorum K>=2 when enough nodes report sharp onsets', () => {
    const two = admitImpulse(threeSharp, { sharpThreshold, quorumK: 2 });
    expect(two.outcome).toBe('claim_admitted');
    expect(two.quorumMet).toBe(true);
    expect(two.sharpCount).toBe(3);

    const three = admitImpulse(threeSharp, { sharpThreshold, quorumK: 3 });
    expect(three.outcome).toBe('claim_admitted');
    expect(three.quorumMet).toBe(true);
  });

  it('downgrades to observation_only when sharp nodes are below quorum', () => {
    const a = admitImpulse(oneSharp, { sharpThreshold, quorumK: 2 });
    expect(a.outcome).toBe('observation_only');
    expect(a.quorumMet).toBe(false);
    expect(a.sharpCount).toBe(1);
  });

  it('refuses to admit at K<2 even when a node is sharp (single-node cannot self-certify)', () => {
    const a = admitImpulse(threeSharp, { sharpThreshold, quorumK: 1 });
    expect(a.outcome).toBe('observation_only');
    expect(a.quorumMet).toBe(false);
    expect(a.summary).toContain('< 2');
  });

  it('withholds when no node reports a sharp onset (sustained sound)', () => {
    const sustainedOnly: NodeReport[] = [
      { sharpness: 10, detected: true },
      { sharpness: 12, detected: true },
    ];
    const a = admitImpulse(sustainedOnly, { sharpThreshold, quorumK: 2 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.quorumMet).toBe(false);
    expect(a.sharpCount).toBe(0);
  });
});

describe('ImpulsiveEventMaster (mirrors impulsive_event_master)', () => {
  it('every boundary witness holds', () => {
    expect(ImpulsiveEventMaster.impulseSharpness).toBe(true);
    expect(ImpulsiveEventMaster.impulseFramesSharp).toBe(true);
    expect(ImpulsiveEventMaster.sustainedSharpness).toBe(true);
    expect(ImpulsiveEventMaster.sustainedFramesNotSharp).toBe(true);
    expect(ImpulsiveEventMaster.threeSharpCount).toBe(true);
    expect(ImpulsiveEventMaster.impulseAdmittedAtTwo).toBe(true);
    expect(ImpulsiveEventMaster.impulseAdmittedAtThree).toBe(true);
    expect(ImpulsiveEventMaster.oneSharpObservationOnly).toBe(true);
    expect(ImpulsiveEventMaster.oneSharpNotAdmitted).toBe(true);
    expect(ImpulsiveEventMaster.sustainedNotCounted).toBe(true);
    expect(ImpulsiveEventMaster.impulseVsSustained).toBe(true);
  });

  it('uses the Lean fixture numbers (sharpThreshold 40, frames, sharpness 87/10)', () => {
    expect(sharpThreshold).toBe(40);
    expect(impulseFrames).toEqual([2, 3, 90, 40, 10]);
    expect(sustainedFrames).toEqual([10, 20, 30, 40, 50]);
    expect(onsetSharpness(impulseFrames)).toBe(87);
    expect(onsetSharpness(sustainedFrames)).toBe(10);
  });
});
